function getImageUrl(name) {
  const key = name.toLowerCase().trim();
  
  // Check silhouettes first
  if (SILHOUETTE_IMAGES[key]) return SILHOUETTE_IMAGES[key];
  
  // Then custom images
  if (CUSTOM_IMAGES[key]) return CUSTOM_IMAGES[key];
  
  const slug = name
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, '')
    .trim()
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-');
  return `https://img.pokemondb.net/sprites/home/normal/2x/${slug}.jpg`;
}

function sp(str) {
  if (!str || str.trim() === '' || str.trim() === '???') return ['???'];
  return str.split(',').map(s => s.trim()).filter(Boolean);
}

function favs(f1, f2, f3, f4, f5) {
  return [f1, f2, f3, f4, f5]
    .map(f => (f || '').trim())
    .filter(f => f && f.toLowerCase() !== 'n/a' && f !== '');
}

function normalizeFav(f) { return f.trim().toLowerCase(); }

